import React from 'react';
import Highcharts from 'highcharts';
import HighchartsReact from 'highcharts-react-official';

const Dashboard = () => {
    const chartOptions = {
        chart: {
            type: 'line'
        },
        title: {
            text: 'Sales Over Time'
        },
        xAxis: {
            categories: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul']
        },
        series: [{
            name: 'Sales',
            data: [30, 40, 35, 50, 49, 60, 70]
        }]
    };

    const barChartOptions = {
        chart: {
            type: 'bar'
        },
        title: {
            text: 'Sales by Month'
        },
        xAxis: {
            categories: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul']
        },
        series: [{
            name: 'Sales',
            data: [20, 30, 25, 40, 35, 50, 60]
        }]
    };

    const pieChartOptions = {
        chart: {
            type: 'pie'
        },
        title: {
            text: 'Inspection Types'
        },
        series: [{
            name: 'Types',
            data: [
                { name: 'Inspections', y: 30 },
                { name: 'Follow-ups', y: 40 },
                { name: 'Re-inspections', y: 30 }
            ]
        }]
    };

    return (
        <div>
            <h1>Dashboard</h1>
            <div className="kpis">
                <div className="kpi">
                    <h2>Total Sales</h2>
                    <p>$100,000</p>
                </div>
                <div className="kpi">
                    <h2>Total Inspections</h2>
                    <p>250</p>
                </div>
                <div className="kpi">
                    <h2>Active Users</h2>
                    <p>150</p>
                </div>
            </div>
            <HighchartsReact
                highcharts={Highcharts}
                options={chartOptions}
            />
            <HighchartsReact
                highcharts={Highcharts}
                options={barChartOptions}
            />
            <HighchartsReact
                highcharts={Highcharts}
                options={pieChartOptions}
            />
        </div>
    );
};

export default Dashboard;
